// // This module compares two 8-bit numbers and outputs whether the first is greater than or equal to the second.
module comparator_8bit (
  input [7:0] a,
  input [7:0] b,
  output lt,
  output eq,
  output gt
);

  assign lt = (a < b);
  assign eq = (a == b);
  assign gt = (a > b);

endmodule
